### 3. 통화(Call) 관련 코드 구조 (예상)

프로젝트가 아직 skeleton 상태이지만, **entity-skill 및 develop 스킬 문서**에 따르면 통화(Call) 관련 코드는 다음과 같은 구조로 구성될 것입니다:

#### 3.1 Entity Layer
**위치**: `domain/src/main/kotlin/com/maum/backend/entity/call/`

```kotlin
@Entity
@Table(catalog = "maum", name = "call")
class CallEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val userId: String,
    val receiverId: String,
    val status: Int,  // 통화 상태 (진행중, 종료, 거부 등)

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

#### 3.2 Repository Layer
**위치**: `domain/src/main/kotlin/com/maum/backend/repository/call/`

```kotlin
interface CallRepository : JpaRepository<CallEntity, String> {
    fun findByUserId(userId: String): List<CallEntity>
    fun findByUserIdAndStatus(userId: String, status: Int): List<CallEntity>
    fun findByReceiverIdAndStatus(receiverId: String, status: Int): List<CallEntity>
}
```

#### 3.3 gRPC Proto 정의
**위치**: `protobuf/src/main/proto/call/call.proto`

```protobuf
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
  rpc GetCall(GetCallRequest) returns (GetCallResponse);
  rpc CreateCall(CreateCallRequest) returns (CreateCallResponse);
  rpc EndCall(EndCallRequest) returns (EndCallResponse);
  rpc ListCalls(ListCallsRequest) returns (ListCallsResponse);
}

message GetCallRequest {
  string user_id = 1;
  string call_id = 2;
}

message GetCallResponse {
  Call call = 1;
}

message Call {
  string id = 1;
  string user_id = 2;
  string receiver_id = 3;
  int32 status = 4;
  string created_at = 5;
  string updated_at = 6;
}
```

#### 3.4 서비스 계층 (Business Logic)
**위치**: `call-service/src/main/kotlin/com/maum/backend/service/` 또는 유사 모듈

```kotlin
@Service
class CallService(
    private val callRepository: CallRepository,
) {
    @Transactional(readOnly = true)
    fun getCall(userId: String, callId: String): CallEntity {
        return callRepository.findById(callId)
            .filter { it.userId == userId || it.receiverId == userId }
            .orElseThrow { NotFoundException("Call not found: $callId") }
    }

    @Transactional
    fun createCall(userId: String, receiverId: String): CallEntity {
        val call = CallEntity(
            userId = userId,
            receiverId = receiverId,
            status = CallStatus.ACTIVE.value
        )
        return callRepository.save(call)
    }
}
```

#### 3.5 gRPC Controller (서버)
**위치**: `call-service/src/main/kotlin/com/maum/backend/controller/CallGrpcService.kt`

```kotlin
@GrpcService
class CallGrpcService(
    private val callService: CallService,
) : CallServiceGrpc.CallServiceImplBase() {

    override fun getCall(
        request: GetCallRequest,
        responseObserver: StreamObserver<GetCallResponse>,
    ) {
        try {
            val call = callService.getCall(request.userId, request.callId)
            val response = GetCallResponse.newBuilder()
                .setCall(call.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }
}
```

#### 3.6 GraphQL Schema
**위치**: `graphql/src/main/resources/graphql/call.graphqls`

```graphql
type Call {
    id: ID!
    user: SimpleUser
    receiver: SimpleUser
    status: String!
    createdAt: String!
    updatedAt: String!
}

input CreateCallInput {
    receiverId: ID!
}

extend type Query {
    call(callId: ID!): Call
    myCalls(limit: Int, offset: Int): [Call!]!
}

extend type Mutation {
    createCall(input: CreateCallInput!): Call!
    endCall(callId: ID!): Boolean!
}
```

#### 3.7 GraphQL Service (gRPC 클라이언트)
**위치**: `graphql/src/main/kotlin/com/maum/backend/service/call/CallService.kt`

```kotlin
@Service
class CallService {
    @GrpcClient("call-grpc")
    private lateinit var stub: CallServiceGrpc.CallServiceBlockingStub

    fun getCall(userId: String, callId: String): GetCallResponse {
        val request = GetCallRequest.newBuilder()
            .setUserId(userId)
            .setCallId(callId)
            .build()
        return try {
            stub.getCall(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

#### 3.8 GraphQL Controller
**위치**: `graphql/src/main/kotlin/com/maum/backend/controller/call/CallController.kt`

```kotlin
@Controller
class CallController(
    private val callService: CallService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun call(
        @UserId userId: String,
        @Argument callId: String,
    ): CallResponse {
        val response = callService.getCall(userId, callId)
        return response.call.toResponse()
    }
}
```

