### 4. 테스트 파일 구조 (아직 미구현)

테스트가 없다는 조건에 따라, 다음과 같은 테스트 파일들이 필요합니다:

#### 4.1 단위 테스트 (Service Layer)
**위치**: `call-service/src/test/kotlin/com/maum/backend/service/CallServiceTest.kt`

```kotlin
@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var repository: CallRepository

    @InjectMocks
    private lateinit var service: CallService

    @Test
    fun `should return call when user is the owner`() {
        // given
        val userId = "user-1"
        val callId = "call-1"
        val callEntity = CallEntity(
            id = callId,
            userId = userId,
            receiverId = "user-2",
            status = CallStatus.ACTIVE.value
        )
        `when`(repository.findById(callId)).thenReturn(Optional.of(callEntity))

        // when
        val result = service.getCall(userId, callId)

        // then
        assertThat(result.id).isEqualTo(callId)
        verify(repository).findById(callId)
    }

    @Test
    fun `should throw when user is not involved in call`() {
        // given
        val callId = "call-1"
        val callEntity = CallEntity(
            id = callId,
            userId = "user-1",
            receiverId = "user-2",
            status = CallStatus.ACTIVE.value
        )
        `when`(repository.findById(callId)).thenReturn(Optional.of(callEntity))

        // when & then
        assertThrows<NotFoundException> {
            service.getCall("user-3", callId)
        }
    }

    @Test
    fun `should throw when call not found`() {
        // given
        `when`(repository.findById("invalid")).thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFoundException> {
            service.getCall("user-1", "invalid")
        }
    }

    @Test
    fun `should create call successfully`() {
        // given
        val userId = "user-1"
        val receiverId = "user-2"
        val savedCall = CallEntity(
            id = "call-1",
            userId = userId,
            receiverId = receiverId,
            status = CallStatus.ACTIVE.value
        )
        `when`(repository.save(any())).thenReturn(savedCall)

        // when
        val result = service.createCall(userId, receiverId)

        // then
        assertThat(result.id).isEqualTo("call-1")
        assertThat(result.status).isEqualTo(CallStatus.ACTIVE.value)
        verify(repository).save(any())
    }
}
```

#### 4.2 gRPC Service 테스트
**위치**: `call-service/src/test/kotlin/com/maum/backend/controller/CallGrpcServiceTest.kt`

```kotlin
@ExtendWith(MockitoExtension::class)
class CallGrpcServiceTest {

    @Mock
    private lateinit var service: CallService

    @InjectMocks
    private lateinit var grpcService: CallGrpcService

    @Test
    fun `should return call via gRPC`() {
        // given
        val request = GetCallRequest.newBuilder()
            .setUserId("user-1")
            .setCallId("call-1")
            .build()
        val responseObserver = mock<StreamObserver<GetCallResponse>>()
        val callEntity = CallEntity(
            id = "call-1",
            userId = "user-1",
            receiverId = "user-2",
            status = CallStatus.ACTIVE.value
        )
        `when`(service.getCall("user-1", "call-1")).thenReturn(callEntity)

        // when
        grpcService.getCall(request, responseObserver)

        // then
        verify(responseObserver).onNext(any())
        verify(responseObserver).onCompleted()
        verify(responseObserver, never()).onError(any())
    }

    @Test
    fun `should return NOT_FOUND error when call not found`() {
        // given
        val request = GetCallRequest.newBuilder()
            .setUserId("user-1")
            .setCallId("invalid")
            .build()
        val responseObserver = mock<StreamObserver<GetCallResponse>>()
        `when`(service.getCall("user-1", "invalid"))
            .thenThrow(NotFoundException("Not found"))

        // when
        grpcService.getCall(request, responseObserver)

        // then
        verify(responseObserver).onError(any(StatusRuntimeException::class.java))
        verify(responseObserver, never()).onCompleted()
    }
}
```

#### 4.3 Repository 통합 테스트
**위치**: `domain/src/test/kotlin/com/maum/backend/repository/call/CallRepositoryTest.kt`

```kotlin
@DataJpaTest
class CallRepositoryTest {

    @Autowired
    private lateinit var repository: CallRepository

    @Test
    fun `should find calls by userId`() {
        // given
        val userId = "user-1"
        val call1 = CallEntity(userId = userId, receiverId = "user-2", status = 0)
        val call2 = CallEntity(userId = userId, receiverId = "user-3", status = 0)
        repository.save(call1)
        repository.save(call2)

        // when
        val result = repository.findByUserId(userId)

        // then
        assertThat(result).hasSize(2)
    }

    @Test
    fun `should find calls by status`() {
        // given
        val userId = "user-1"
        val activeCall = CallEntity(userId = userId, receiverId = "user-2", status = 0)
        val endedCall = CallEntity(userId = userId, receiverId = "user-3", status = 1)
        repository.save(activeCall)
        repository.save(endedCall)

        // when
        val result = repository.findByUserIdAndStatus(userId, 0)

        // then
        assertThat(result).hasSize(1)
        assertThat(result[0].status).isEqualTo(0)
    }

    @Test
    fun `should find calls by receiver`() {
        // given
        val receiverId = "user-2"
        val call = CallEntity(userId = "user-1", receiverId = receiverId, status = 0)
        repository.save(call)

        // when
        val result = repository.findByReceiverIdAndStatus(receiverId, 0)

        // then
        assertThat(result).hasSize(1)
    }
}
```

