@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var repository: CallRepository

    @InjectMocks
    private lateinit var service: CallService

    @Test
    fun `should return call when user is the owner`() {
        // given
        val userId = "user-1"
        val callId = "call-1"
        val callEntity = CallEntity(
            id = callId,
            userId = userId,
            receiverId = "user-2",
            status = CallStatus.ACTIVE.value
        )
        `when`(repository.findById(callId)).thenReturn(Optional.of(callEntity))

        // when
        val result = service.getCall(userId, callId)

        // then
        assertThat(result.id).isEqualTo(callId)
        verify(repository).findById(callId)
    }

    @Test
    fun `should throw when user is not involved in call`() {
        // given
        val callId = "call-1"
        val callEntity = CallEntity(
            id = callId,
            userId = "user-1",
            receiverId = "user-2",
            status = CallStatus.ACTIVE.value
        )
        `when`(repository.findById(callId)).thenReturn(Optional.of(callEntity))

        // when & then
        assertThrows<NotFoundException> {
            service.getCall("user-3", callId)
        }
    }

    @Test
    fun `should throw when call not found`() {
        // given
        `when`(repository.findById("invalid")).thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFoundException> {
            service.getCall("user-1", "invalid")
        }
    }

    @Test
    fun `should create call successfully`() {
        // given
        val userId = "user-1"
        val receiverId = "user-2"
        val savedCall = CallEntity(
            id = "call-1",
            userId = userId,
            receiverId = receiverId,
            status = CallStatus.ACTIVE.value
        )
        `when`(repository.save(any())).thenReturn(savedCall)

        // when
        val result = service.createCall(userId, receiverId)

        // then
        assertThat(result.id).isEqualTo("call-1")
        assertThat(result.status).isEqualTo(CallStatus.ACTIVE.value)
        verify(repository).save(any())
    }
}
